import { NavBar } from "./NavBar";
import { Footer } from "./Footer";
import { useState, useRef, useEffect } from "react";
import pattern from "../slike/pattern4.jpg";
import { useNavigate } from "react-router-dom";

export function Login() {
  const [email, setEmail] = useState("");
  const [lozinkaHash, setLozinka] = useState("");
  const imeRef = useRef(null);
  const navigate = useNavigate();

  useEffect(() => {
    imeRef.current.focus();
  }, []);

  // Funkcija za login (razlikuje gosta i recepcionara po role parametru)
  const handleSubmit = async (e, role) => {
    e.preventDefault();

    try {
      // Backend endpoint zavisi od tipa korisnika
      const url =
        role === "admin"
          ? `http://localhost:8080/admin/login/${email}/${lozinkaHash}`
          : `http://localhost:8080/guests/login/${email}/${lozinkaHash}`;

      const response = await fetch(url, { method: "GET" });

      if (response.ok) {
        const data = await response.json();

        if (role === "gost") {
          const guest = data.data.guest;

          // Čuvamo podatke u kolačićima (gost)
          document.cookie = `userEmail=${guest.email}; path=/;`;
          document.cookie = `userId=${guest.idGost}; path=/;`;

          // Preusmeravanje gosta na početnu stranu
          navigate("/");
        } else {
          const admin = data.data.admin;

          // Čuvamo podatke u kolačićima (recepcionar)
          document.cookie = `adminEmail=${admin.email}; path=/;`;
          document.cookie = `adminId=${admin.idAdmin}; path=/;`;

          // ✅ Preusmeravanje recepcionara na njegovu početnu stranu
          navigate("/recepcionar/pocetna");
        }
      } else {
        alert("Pogrešno uneti podaci!");
      }
    } catch (error) {
      console.error("Greška prilikom login-a:", error);
      alert("Server nije dostupan.");
    }
  };

  return (
    <>
      <NavBar />
      <div
        style={{
          backgroundImage: `url(${pattern})`,
          backgroundSize: "cover",
          backgroundPosition: "center",
          minHeight: "100vh",
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          flexDirection: "column",
        }}
      >
        <div className="forma" style={{ width: "300px", height: "300px" }}>
          <form>
            <span className="formaSpan">
              Unesite email
              <input
                type="email"
                onChange={(e) => setEmail(e.target.value)}
                ref={imeRef}
                required
              />
            </span>

            <span className="formaSpan">
              Unesite lozinku
              <input
                type="password"
                onChange={(e) => setLozinka(e.target.value)}
                required
              />
            </span>

            {/* Dva dugmeta - jedno za gosta, drugo za recepcionara */}
            <div style={{ marginTop: "20px" }}>
              <button
                onClick={(e) => handleSubmit(e, "gost")}
                className="btnNav"
                style={{
                  marginRight: "10px",
                  border: "none",
                  fontSize: "18px",
                  width: "160px",
                  height: "50px",
                }}
              >
                Uloguj se
              </button>

              <button
                onClick={(e) => handleSubmit(e, "admin")}
                className="btnNav"
                style={{
                  border: "none",
                  fontSize: "18px",
                  width: "200px",
                  height: "50px",
                  fontSize: "18px",
                  backgroundColor: "#c0c0c0",
                }}
              >
                Uloguj se kao recepcionar
              </button>
            </div>
          </form>
        </div>
      </div>
      <Footer />
    </>
  );
}
